const brandItems    = $('clean_brand_report').all();
const shoppingItems = $('clean_shopping_queries').all();
const searchItems   = $('clean_search_queries').all();
const domainItems   = $('clean_domain_reports').all();

return [{
  json: {
    brand_intel:      brandItems.length > 0 ? brandItems[0].json : null,
    shopping_queries: shoppingItems.length > 0 ? shoppingItems[0].json : null,
    search_queries:   searchItems.length > 0 ? searchItems[0].json : null,
    domain_report:    domainItems.length > 0 ? domainItems[0].json : null,
  }
}];

const items = $input.all();
const results = [];

// Sentiment range → tier
function sentimentTier(sent) {
  if (sent <= 44) return { label: 'bad',    weight: 3 };
  if (sent <= 65) return { label: 'normal', weight: 2 };
  return                  { label: 'good',  weight: 1 };
}

function extractContent(rawData) {
  let content = rawData.content;
  if (Array.isArray(content)) content = content[0];
  if (content && content.text) content = content.text;
  if (!content || !content.columns) content = rawData;
  if (!content || !content.columns) return null;
  return content;
}

function buildIdx(columns) {
  const findIdx = (name) => columns.findIndex(c => c.toLowerCase() === name.toLowerCase());
  return {
    name:      findIdx('brand_name'),
    visibility: findIdx('visibility'),
    vis_count:  findIdx('visibility_count'),
    vis_total:  findIdx('visibility_total'),
    sov:        findIdx('share_of_voice'),
    sentiment:  findIdx('sentiment'),
    pos:        findIdx('position'),
    is_own:     findIdx('is_own'),
  };
}

function parseBrandRow(row, idx) {
  const name     = row[idx.name];
  const isOwn    = idx.is_own !== -1 ? (row[idx.is_own] === true || row[idx.is_own] === 'true') : false;
  const vis      = parseFloat(row[idx.visibility]) || 0;
  const sent     = parseFloat(row[idx.sentiment])  || 0;
  const pos      = parseFloat(row[idx.pos])        || 0;
  const sov      = parseFloat(row[idx.sov])        || 0;
  const visCount = parseFloat(row[idx.vis_count])  || 0;
  const visTotal = parseFloat(row[idx.vis_total])  || 1;

  const tier               = sentimentTier(sent);
  const vulnerabilityScore = pos > 0 && pos <= 5
    ? parseFloat(((100 - sent) / pos).toFixed(2))
    : 0;
  const saturation         = parseFloat(((visCount / visTotal) * 100).toFixed(1));

  let status = 'Stable';
  let tacticalAdvice = 'Maintain authority.';
  if (tier.label === 'bad' && pos > 0 && pos <= 5) {
    status = 'Vulnerable (Target for Attack)';
    tacticalAdvice = `HIGH PRIORITY: ${name} is visible but has poor sentiment (${sent}).`;
  } else if (vis < 0.3 && saturation < 20) {
    status = 'Blue Ocean';
    tacticalAdvice = `OPPORTUNITY: Low visibility and low saturation — untapped market.`;
  }

  return { name, isOwn, vis, sent, sov, pos, visCount, visTotal, tier, vulnerabilityScore, saturation, status, tacticalAdvice };
}

// ── items[0] = yesterday (prev), items[1] = today (curr) ─────
const prevContent = items[1] ? extractContent(items[0]?.json) : null;
const currContent = extractContent(items[items.length - 1]?.json);

if (!currContent) return results;

const currIdx = buildIdx(currContent.columns);
const currBrands = (currContent.rows || []).map(row => parseBrandRow(row, currIdx));

// Index previous day by brand name (if available)
const prevByBrand = {};
if (prevContent) {
  const prevIdx = buildIdx(prevContent.columns);
  for (const row of (prevContent.rows || [])) {
    const b = parseBrandRow(row, prevIdx);
    prevByBrand[b.name] = b;
  }
}

const hasPrev = Object.keys(prevByBrand).length > 0;

const brandAnalysis = currBrands.map(b => {
  const prev = prevByBrand[b.name];

  const evolution = prev ? {
    visibility_delta: parseFloat((b.vis  - prev.vis).toFixed(3)),
    sentiment_delta:  parseFloat((b.sent - prev.sent).toFixed(1)),
    position_delta:   parseFloat((b.pos  - prev.pos).toFixed(1)),
    trend: b.vis > prev.vis ? 'up' : b.vis < prev.vis ? 'down' : 'stable',
  } : null;

  return {
    brand:               b.name,
    is_own:              b.isOwn,
    visibility:          b.vis,
    sentiment:           b.sent,
    sentiment_tier:      b.tier.label,
    position:            b.pos,
    sov:                 b.sov,
    saturation:          b.saturation,
    market_status:       b.status,
    tactical_advice:     b.tacticalAdvice,
    vulnerability_score: b.vulnerabilityScore,
    evolution,
  };
});

const opportunities = brandAnalysis.filter(b => b.market_status !== 'Stable');

results.push({
  json: {
    source:            'get_brand_report',
    detailed_analysis: brandAnalysis,
    opportunity_count: opportunities.length,
    has_evolution:     hasPrev,
    timestamp:         new Date().toISOString(),
  }
});

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const rawData = item.json;

  let content = rawData.content;
  if (Array.isArray(content)) content = content[0];
  if (content && content.text) content = content.text;
  if (!content || !content.columns) content = rawData;
  if (!content || !content.columns) continue;

  const columns = content.columns;
  const rows = content.rows || [];

  const findIdx = (name) => columns.findIndex(c => c.toLowerCase() === name.toLowerCase());

  const idx = {
    id:       findIdx('id'),
    text:     findIdx('text'),
    tag_ids:  findIdx('tag_ids'),
    topic_id: findIdx('topic_id'),
    volume:   findIdx('volume'),
  };

  const volumeScore = { low: 1, medium: 2, high: 3 };

  const classifyIntent = (text) => {
    const t = text.toLowerCase();
    if (/\b(buy|shop|store|where can i|best place)\b/.test(t)) return 'purchase_intent';
    if (/\b(compare|analyze|analyse|evaluate|market positioning)\b/.test(t)) return 'research_intent';
    if (/\b(suggest|recommend)\b/.test(t)) return 'recommendation_intent';
    if (/\b(best|top|top-rated|leading)\b/.test(t)) return 'discovery_intent';
    if (/\b(find|identify|locate|list|show me)\b/.test(t)) return 'discovery_intent';
    return 'general';
  };

  const queries = rows.map(row => {
    const text = row[idx.text] || '';
    return {
      id:           row[idx.id],
      text:         text,
      tag_ids:      row[idx.tag_ids] || [],
      topic_id:     row[idx.topic_id],
      volume:       row[idx.volume] || 'low',
      volume_score: volumeScore[row[idx.volume]] || 1,
      intent_type:  classifyIntent(text),
    };
  });

  // 依 volume_score 降冪排序，同分再按 intent 優先購買意圖
  queries.sort((a, b) => {
    if (b.volume_score !== a.volume_score) return b.volume_score - a.volume_score;
    const intentPriority = { purchase_intent: 3, discovery_intent: 2, recommendation_intent: 1, research_intent: 0, general: 0 };
    return (intentPriority[b.intent_type] || 0) - (intentPriority[a.intent_type] || 0);
  });

  const intentSummary = queries.reduce((acc, q) => {
    acc[q.intent_type] = (acc[q.intent_type] || 0) + 1;
    return acc;
  }, {});

  results.push({
    json: {
      source:         'list_shopping_queries',
      total:          queries.length,
      intent_summary: intentSummary,
      queries:        queries,
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const rawData = item.json;

  let content = rawData.content;
  if (Array.isArray(content)) content = content[0];
  if (content && content.text) content = content.text;
  if (!content || !content.columns) content = rawData;
  if (!content || !content.columns) continue;

  const columns = content.columns;
  const rows = content.rows || [];

  const findIdx = (name) => columns.findIndex(c => c.toLowerCase() === name.toLowerCase());

  const idx = {
    prompt_id:        findIdx('prompt_id'),
    chat_id:          findIdx('chat_id'),
    model_id:         findIdx('model_id'),
    model_channel_id: findIdx('model_channel_id'),
    date:             findIdx('date'),
    query_index:      findIdx('query_index'),
    query_text:       findIdx('query_text'),
  };

  // 從 query_text 萃取出現的品牌名稱（可依實際品牌清單調整）
  const KNOWN_BRANDS = [
    'lululemon', 'nike', 'adidas', 'alo', 'gymshark', 'vuori',
    'athleta', 'under armour', 'puma', 'rhone', 'beyond yoga',
    'sweaty betty', 'skims', 'fabletics'
  ];

  const extractBrands = (text) => {
    const t = text.toLowerCase();
    return KNOWN_BRANDS.filter(b => t.includes(b));
  };

  // 整理每一筆 query
  const allQueries = rows.map(row => ({
    prompt_id:        row[idx.prompt_id],
    chat_id:          row[idx.chat_id],
    model_id:         row[idx.model_id],
    model_channel_id: row[idx.model_channel_id],
    date:             row[idx.date],
    query_index:      row[idx.query_index],
    query_text:       row[idx.query_text] || '',
    brands_mentioned: extractBrands(row[idx.query_text] || ''),
  }));

  // 依 prompt_id 分組，了解每個 prompt 在各 model 產生了哪些搜尋詞
  const byPrompt = {};
  for (const q of allQueries) {
    if (!byPrompt[q.prompt_id]) byPrompt[q.prompt_id] = [];
    byPrompt[q.prompt_id].push(q);
  }

  // 依 model_id 統計查詢數量分佈
  const modelDistribution = allQueries.reduce((acc, q) => {
    acc[q.model_id] = (acc[q.model_id] || 0) + 1;
    return acc;
  }, {});

  // 所有 query_text 去重後的關鍵字池（了解 AI 用哪些詞搜尋這個市場）
  const uniqueQueryTexts = [...new Set(allQueries.map(q => q.query_text))];

  // 在 query_text 中出現的品牌統計（AI 主動帶入品牌名稱的頻率）
  const brandMentionCount = {};
  for (const q of allQueries) {
    for (const brand of q.brands_mentioned) {
      brandMentionCount[brand] = (brandMentionCount[brand] || 0) + 1;
    }
  }

  // 按提及次數排序
  const brandMentionRanking = Object.entries(brandMentionCount)
    .sort((a, b) => b[1] - a[1])
    .map(([brand, count]) => ({ brand, count }));

  results.push({
    json: {
      source:                'list_search_queries',
      total_queries:         allQueries.length,
      unique_query_texts:    uniqueQueryTexts.length,
      model_distribution:    modelDistribution,
      brand_mention_ranking: brandMentionRanking,
      unique_keywords:       uniqueQueryTexts,
      by_prompt:             byPrompt,
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const rawData = item.json;

  let content = rawData.content;
  if (Array.isArray(content)) content = content[0];
  if (content && content.text) content = content.text;
  if (!content || !content.columns) content = rawData;
  if (!content || !content.columns) continue;

  const columns = content.columns;
  const rows    = content.rows || [];

  const findIdx = (name) => columns.findIndex(c => c.toLowerCase() === name.toLowerCase());

  const idx = {
    domain:              findIdx('domain'),
    classification:      findIdx('classification'),
    retrieved_pct:       findIdx('retrieved_percentage'),
    retrieval_rate:      findIdx('retrieval_rate'),
    citation_rate:       findIdx('citation_rate'),
    mentioned_brand_ids: findIdx('mentioned_brand_ids'),
  };

  const domains = rows.map(row => ({
    domain:              row[idx.domain],
    classification:      row[idx.classification],
    retrieved_pct:       parseFloat(row[idx.retrieved_pct])       || 0,  // 0–1，顯示時 ×100
    retrieval_rate:      parseFloat(row[idx.retrieval_rate])      || 0,  // 直接顯示
    citation_rate:       parseFloat(row[idx.citation_rate])       || 0,  // 可超過 1.0，直接顯示
    mentioned_brand_ids: row[idx.mentioned_brand_ids]             || [],
  }));

  // 依 classification 分組
  const byClass = domains.reduce((acc, d) => {
    if (!acc[d.classification]) acc[d.classification] = [];
    acc[d.classification].push(d);
    return acc;
  }, {});

  const ownDomains        = byClass['OWN']        || [];
  const competitorDomains = (byClass['COMPETITOR'] || []).sort((a, b) => b.citation_rate - a.citation_rate);
  const ugcDomains        = (byClass['UGC']        || []).sort((a, b) => b.citation_rate - a.citation_rate);

  // Gap score: 衡量此域名對市場的影響力，但自有品牌尚未在此建立存在感
  // gap_score = citation_rate × retrieval_rate
  // citation_rate 高 → AI 頻繁引用此域名
  // retrieval_rate 高 → AI 頻繁檢索此域名作為資料來源
  // 兩者都高 → 此域名對 AI 推薦影響極大，是優先投資標的
  const GAP_TYPES = ['EDITORIAL', 'REFERENCE', 'UGC'];

  const investmentCandidates = domains
    .filter(d => GAP_TYPES.includes(d.classification))
    .map(d => ({
      ...d,
      gap_score: parseFloat((d.citation_rate * d.retrieval_rate).toFixed(4)),
    }))
    .sort((a, b) => b.gap_score - a.gap_score);

  // 分類後的投資建議（各類型前 5，再合併去重後取前 10）
  const topByType = {};
  for (const type of GAP_TYPES) {
    topByType[type] = investmentCandidates
      .filter(d => d.classification === type)
      .slice(0, 5);
  }

  const seen = new Set();
  const domain_investment_suggestion = investmentCandidates
    .filter(d => {
      if (seen.has(d.domain)) return false;
      seen.add(d.domain);
      return true;
    })
    .slice(0, 10)
    .map(d => ({
      domain:          d.domain,
      classification:  d.classification,
      citation_rate:   d.citation_rate,
      retrieval_rate:  d.retrieval_rate,
      gap_score:       d.gap_score,
      why: d.classification === 'EDITORIAL'
        ? '高權威媒體，AI 頻繁引用，適合投稿或品牌合作'
        : d.classification === 'REFERENCE'
        ? '參考型來源（如維基百科），AI 信任度最高，優先建立品牌條目'
        : 'UGC 平台，真實用戶評論驅動 AI 搜尋推薦',
    }));

  // 高引用域名（citation_rate > 1.0），排除已是自有域名者
  const ownSet = new Set(ownDomains.map(d => d.domain));
  const highCitationDomains = domains
    .filter(d => d.citation_rate > 1.0 && !ownSet.has(d.domain))
    .sort((a, b) => b.citation_rate - a.citation_rate);

  results.push({
    json: {
      source:                      'get_domain_report',
      total_domains:               domains.length,
      own_domains:                 ownDomains,
      competitor_domains:          competitorDomains,
      ugc_domains:                 ugcDomains,
      high_citation_domains:       highCitationDomains,
      domain_investment_suggestion,
      investment_by_type:          topByType,
      by_classification:           byClass,
    }
  });
}

return results;

const allItems = $input.all();

// AI Agent output — first item with an `output` field
const agentItem = allItems.find(i => i.json.output !== undefined) || allItems[0];
const raw = agentItem.json;

// Parse JSON from AI Agent output (handles string or object)
function extractJSON(str) {
  const start = str.search(/[{[]/);
  if (start === -1) return str;
  let depth = 0, inString = false, escape = false;
  for (let i = start; i < str.length; i++) {
    const ch = str[i];
    if (escape) { escape = false; continue; }
    if (ch === '\\' && inString) { escape = true; continue; }
    if (ch === '"') { inString = !inString; continue; }
    if (inString) continue;
    if (ch === '{' || ch === '[') depth++;
    if (ch === '}' || ch === ']') { depth--; if (depth === 0) return str.slice(start, i + 1); }
  }
  return str.slice(start);
}

let data;
if (typeof raw.output === 'string') {
  const stripped = raw.output.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  data = JSON.parse(extractJSON(stripped));
} else if (typeof raw.output === 'object' && raw.output !== null) {
  data = raw.output;
} else {
  data = raw;
}

// Brand report from clean_brand_report.js (passed via Merge node)
const brandReportItem = allItems.find(i => i.json.source === 'get_brand_report');
const allBrands = brandReportItem?.json?.detailed_analysis || [];

// Content strategy matrix items from combine_strategy_with_docs.js
const strategyItems = allItems.filter(i => i.json.documentId && i.json.content_format);

const d = data;
const date = d.report_date || new Date().toISOString().slice(0, 10);

const lines = [];

// ── Header ────────────────────────────────────────────────────
lines.push(`# Strategic Conquest Dashboard — ${date}`);
lines.push('');

// ══════════════════════════════════════════════════════════════
// PART 1 · Battlefield Alert
// Lead with real-time sentiment & visibility signals (defensive radar)
// ══════════════════════════════════════════════════════════════
lines.push('## PART 1 · Battlefield Alert');
lines.push('*Brand Asset Erosion Warning — real-time signals from the AI battlefield*');
lines.push('');

if ((d.evolution_highlights || []).length > 0) {
  d.evolution_highlights.forEach(e => {
    const arrow = e.trend === 'up' ? '↑' : e.trend === 'down' ? '↓' : '→';
    const fmt = (n) => (n > 0 ? `+${n}` : `${n}`);
    const alertIcon = e.trend === 'down' ? '🔴' : e.trend === 'up' ? '🟢' : '🟡';
    lines.push(`> ${alertIcon} ${arrow} **${e.brand}** (Visibility ${fmt(e.visibility_delta)}) — ${e.insight}`);
  });
  lines.push('');
}

const ob = d.own_brand_summary;
if (ob) {
  lines.push(`### Brand Status — ${ob.brand}`);
  const bi = ob.brand_intel || {};
  const sp = ob.search_presence || {};
  const dp = ob.domain_presence || {};

  lines.push('| Metric | Value |');
  lines.push('|--------|-------|');
  lines.push(`| Visibility | ${bi.visibility ?? '—'} |`);
  lines.push(`| Sentiment Score | ${bi.sentiment ?? '—'} |`);
  lines.push(`| Position | ${bi.position ?? '—'} |`);
  lines.push(`| Share of Voice (SoV) | ${bi.share_of_voice ?? '—'} |`);
  lines.push(`| Market Status | ${bi.market_status ?? '—'} |`);
  lines.push(`| Vulnerability Score | ${bi.vulnerability_score ?? '—'} |`);
  lines.push(`| AI Search Mention Ranking | ${sp.brand_mention_ranking ?? '—'} |`);
  lines.push(`| Avg. Citation Rate | ${dp.avg_citation_rate ?? '—'} |`);
  lines.push(`| Avg. Retrieval Rate | ${dp.avg_retrieval_rate ?? '—'} |`);
  lines.push(`| Cited Domains | ${(dp.own_domains_cited || []).join(', ') || '—'} |`);
  lines.push('');
  lines.push('> **Vulnerability Score Explained**');
  lines.push('> Formula: `(100 − Sentiment Score) ÷ Position` — calculated for top-5 ranked brands only');
  lines.push('> Higher score = more visible but poorer reputation = higher attack priority');
  lines.push('> Sentiment tiers: 0–44 Poor  45–65 Fair  66–100 Good');
  lines.push('');

  if ((sp.unique_keywords || []).length > 0) {
    lines.push(`**Related Keywords:** ${sp.unique_keywords.join(', ')}`);
    lines.push('');
  }

  if (ob.raw_summary) {
    lines.push(ob.raw_summary);
    lines.push('');
  }
}

// ══════════════════════════════════════════════════════════════
// PART 2 · Vulnerability Radar
// Competitor weakness scan — ranked by attack priority
// ══════════════════════════════════════════════════════════════
lines.push('## PART 2 · Vulnerability Radar');
lines.push('*Competitor weakness scan — ranked by attack priority*');
lines.push('');

const competitors = allBrands.filter(b => !b.is_own);
if (competitors.length > 0) {
  lines.push('### Competitor Metrics & Daily Evolution');
  lines.push('<!-- COMPETITORS_CHART -->');
  lines.push('');
}

lines.push('### Competitive Landscape Overview');
lines.push('<!-- RADAR_CHART -->');
lines.push('<!-- COMPETITIVE_LANDSCAPE -->');
lines.push('');

const cs = d.competitive_summary || {};


// ══════════════════════════════════════════════════════════════
// PART 3 · Execution Matrix (Live)
// Closed loop: Monitor → Analyze → Direct → Execute
// ══════════════════════════════════════════════════════════════
lines.push('## PART 3 · Execution Matrix (Live)');
lines.push('*Closed loop: Monitor → Analyze → Direct → Execute*');
lines.push('');

if ((d.action_plan || []).length > 0) {
  lines.push('### Action Commands');
  lines.push('| Priority | Timeframe | Action Item | Rationale |');
  lines.push('|----------|-----------|-------------|-----------|');
  d.action_plan.forEach(a => {
    const priority = (a.priority || '').toUpperCase();
    lines.push(`| ${priority} | ${a.timeframe} | ${a.action} | ${a.rationale} |`);
  });
  lines.push('');
}

if (strategyItems.length > 0) {
  lines.push('### Content Deployment Briefs');
  strategyItems.forEach((item, idx) => {
    if (idx > 0) lines.push('---');
    const s = item.json;
    const docUrl = `https://docs.google.com/document/d/${s.documentId}`;
    const priorityLabel = (s.priority || '').toUpperCase();
    lines.push(`#### [${priorityLabel}] ${s.platform} — ${s.platform_type}`);
    lines.push(`**Format:** ${s.content_format}`);
    lines.push(`**Audience:** ${s.audience}`);
    lines.push(`**Content Brief:** ${s.content_brief}`);
    if (s.reference_insight) lines.push(`**Reference Insight:** ${s.reference_insight}`);
    lines.push(`**Document:** [Open Google Doc](${docUrl})`);
    lines.push('');
  });
}

lines.push('---');
lines.push('*This dashboard is a living document. Peec AI refreshes competitive signals every 6 hours.*');

const markdown = lines.join('\n');

return [
  { json: { ...data, allBrands } },
  { json: { markdown } },
];

const raw = $input.first().json;

// Parse AI Agent output (handles string or object)
function extractJSON(str) {
  const start = str.search(/[{[]/);
  if (start === -1) return str;
  let depth = 0, inString = false, escape = false;
  for (let i = start; i < str.length; i++) {
    const ch = str[i];
    if (escape) { escape = false; continue; }
    if (ch === '\\' && inString) { escape = true; continue; }
    if (ch === '"') { inString = !inString; continue; }
    if (inString) continue;
    if (ch === '{' || ch === '[') depth++;
    if (ch === '}' || ch === ']') { depth--; if (depth === 0) return str.slice(start, i + 1); }
  }
  return str.slice(start);
}

let data;
if (typeof raw.output === 'string') {
  const stripped = raw.output.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  data = JSON.parse(extractJSON(stripped));
} else if (typeof raw.output === 'object' && raw.output !== null) {
  data = raw.output;
} else {
  data = raw;
}

return [{
  json: {
    report_date:          data.report_date,
    action_plan:          data.action_plan          || [],
    market_opportunities: data.market_opportunities || [],
    content_strategy:     data.content_strategy     || {},
    copy_brief:           data.copy_brief           || {},
  }
